'use client';
import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useRouter, useSearchParams } from 'next/navigation';
import { Menu, ChevronLeft, Plus, SlidersHorizontal, ChevronUp, ChevronDown, Search, X, ChevronRight } from 'lucide-react';
import { TemplateFilterSidebar } from '@/components/shared/TemplateFilterSidebar';
import { allTemplates } from '@/components/shared/TemplateSectionData';
import TemplateCard from '@/components/shared/TemplateCard';
import FeaturedTemplateCard from '@/components/shared/FeaturedTemplateCard';

export function TemplateGallery() {
  const router = useRouter();
  const searchParams = useSearchParams();
  
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [roleFilters, setRoleFilters] = useState<string[]>([]);
  const [useCaseFilters, setUseCaseFilters] = useState<string[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  const initialCategory = searchParams.get('category') || '';
  const [categoryFilter, setCategoryFilter] = useState(initialCategory);

  useEffect(() => {
    const category = searchParams.get('category');
    if (category) {
      setCategoryFilter(category);
    }
  }, [searchParams]);

  const handleRoleToggle = (role: string) => {
    setRoleFilters(prev => 
      prev.includes(role) ? prev.filter(r => r !== role) : [...prev, role]
    );
  };

  const handleUseCaseToggle = (useCase: string) => {
    setUseCaseFilters(prev => 
      prev.includes(useCase) ? prev.filter(u => u !== useCase) : [...prev, useCase]
    );
  };

  const filteredTemplates = allTemplates.filter(t => {
    if (categoryFilter && t.category !== categoryFilter) {
      return false;
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      if (!t.title.toLowerCase().includes(q) && !t.description.toLowerCase().includes(q)) {
        return false;
      }
    }
    if (roleFilters.length > 0 && !t.roles.some(r => roleFilters.includes(r))) {
      return false;
    }
    if (useCaseFilters.length > 0 && !t.useCases.some(u => useCaseFilters.includes(u))) {
      return false;
    }
    return true;
  });

  const handleNewAgent = () => {
    console.log('POST /api/agents', { name: undefined });
    router.push('/agents/mock-agent-id/configure');
  };

  const handleBack = () => {
    router.push('/home');
  };

  const mostPopularTemplates = filteredTemplates.filter(t => t.category === 'most_popular');
  const featured = mostPopularTemplates.find(t => t.isFeatured);
  const regulars = mostPopularTemplates.filter(t => !t.isFeatured);

  return (
    <div className="min-h-screen bg-gradient-to-br from-amber-50/40 via-yellow-50/30 to-white pb-24 selection:bg-blue-100 selection:text-blue-900">
      {/* Top bar */}
      <div className="flex items-center justify-between px-4 md:px-6 py-3 border-b border-gray-100">
        <div className="flex items-center gap-3">
          <button onClick={() => console.log('Toggle sidebar menu (Desktop Layout)')} className="text-gray-600 p-1.5 hover:bg-gray-100 rounded-lg focus:outline-none focus:ring-2 focus:ring-gray-300">
            <Menu className="w-5 h-5" />
          </button>
          <button onClick={handleBack} className="flex items-center gap-1 text-sm text-gray-700 hover:text-gray-900 font-medium focus:outline-none focus:ring-2 focus:ring-gray-300 rounded px-1" aria-label="Back to home">
            <ChevronLeft className="w-4 h-4 text-gray-500" /> Back
          </button>
        </div>
        <button
          onClick={handleNewAgent}
          className="border border-gray-200 rounded-lg px-4 py-2 text-sm font-medium text-gray-900 bg-white hover:bg-gray-50 flex items-center gap-1.5 shadow-sm focus:outline-none focus:ring-2 focus:ring-gray-200 transition-all"
        >
          <Plus className="w-4 h-4 text-gray-400" strokeWidth={2.5} /> New Agent
        </button>
      </div>

      {/* Mobile filter toggle — visible only on mobile/tablet */}
      <div className="md:hidden px-4 md:px-6 mb-3">
        <button
          onClick={() => setFiltersOpen(!filtersOpen)}
          className="flex items-center gap-2 text-sm font-medium text-gray-700 border border-gray-200 rounded-lg px-3 py-2 hover:bg-gray-50 shadow-sm bg-white focus:outline-none focus:ring-2 focus:ring-gray-200 w-full justify-center transition"
          aria-expanded={filtersOpen}
        >
          <SlidersHorizontal className="w-4 h-4 text-gray-500" />
          Filters
          {filtersOpen ? <ChevronUp className="w-4 h-4 text-gray-400" /> : <ChevronDown className="w-4 h-4 text-gray-400" />}
        </button>
      </div>

      {/* Body: sidebar + content — stacks on mobile, side-by-side on desktop */}
      <div className="flex flex-col md:flex-row px-4 md:px-6 gap-6 md:gap-8 mt-2 max-w-[1400px] mx-auto">
        
        {/* Sidebar — always visible on desktop, toggle on mobile */}
        <div className={`${filtersOpen ? 'block animate-in fade-in slide-in-from-top-2' : 'hidden'} md:block`}>
          <TemplateFilterSidebar 
            roleFilters={roleFilters}
            useCaseFilters={useCaseFilters}
            onRoleToggle={handleRoleToggle}
            onUseCaseToggle={handleUseCaseToggle}
          />
        </div>

        <div className="flex-1 max-w-full md:max-w-4xl">
          
          {/* Active Category Filter Chip */}
          {categoryFilter && (
            <div className="flex items-center gap-2 mb-3">
              <span className="text-xs text-gray-500">Filtered by:</span>
              <button
                onClick={() => setCategoryFilter('')}
                className="flex items-center gap-1 bg-gray-100 rounded-full px-3 py-1 text-sm text-gray-700 hover:bg-gray-200 focus:outline-none focus:ring-2 focus:ring-gray-300"
              >
                {categoryFilter.replace(/_/g, ' ')}
                <X className="w-3 h-3 text-gray-500" />
              </button>
            </div>
          )}

          {/* Search */}
          <div className="relative max-w-full md:max-w-2xl group">
            <Search className="w-5 h-5 text-gray-400 absolute left-4 top-1/2 -translate-y-1/2 transition-colors group-focus-within:text-blue-500" />
            <input
              type="text"
              placeholder="Search"
              aria-label="Search templates"
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              className="w-full border border-gray-200/80 rounded-[12px] pl-[42px] pr-4 py-3 text-sm outline-none focus:border-blue-500/50 focus:ring-4 focus:ring-blue-500/10 transition-all shadow-sm bg-white"
            />
          </div>

          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Most popular section */}
            {mostPopularTemplates.length > 0 && (
              <section className="mt-6 md:mt-8">
                <div className="flex items-center justify-between mb-4 md:mb-[16px] px-1">
                  <h2 className="text-lg font-semibold tracking-tight text-gray-900">Most popular</h2>
                  <span className="text-[13px] font-medium text-gray-600 hover:text-gray-900 transition-colors flex items-center cursor-pointer">
                    See all <ChevronRight className="w-4 h-4 ml-0.5" />
                  </span>
                </div>

                {/* Row 1: Featured (3 cols) + Regular (2 cols) on desktop */}
                <div className="grid grid-cols-1 md:grid-cols-5 gap-[14px] mt-4">
                  {featured && (
                    <div className="col-span-1 md:col-span-3">
                      <FeaturedTemplateCard template={featured} />
                    </div>
                  )}
                  {regulars[0] && (
                    <div className="col-span-1 md:col-span-2">
                      <TemplateCard template={regulars[0]} />
                    </div>
                  )}
                </div>

                {/* Row 2: remaining regular cards */}
                {regulars.length > 1 && (
                  <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-[14px] mt-4">
                    {regulars.slice(1, 4).map(t => (
                      <TemplateCard key={t.id} template={t} />
                    ))}
                  </div>
                )}
              </section>
            )}

            {/* All templates section */}
            <section className="mt-10 mb-12">
              <h2 className="text-lg font-semibold tracking-tight text-gray-900 px-1 mb-4 md:mb-[16px]">All templates</h2>
              
              {filteredTemplates.filter(t => !t.isFeatured).length > 0 ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-[14px] mt-4">
                  {/* For 'All templates', display everything EXCEPT the featured banner styles to keep the grid even */}
                  {filteredTemplates.filter(t => !t.isFeatured).map(template => (
                    <TemplateCard key={template.id} template={template} />
                  ))}
                  {/* If Most Popular Featured happens to be the ONLY thing matching, display it anyway but in standard card block */}
                  {filteredTemplates.filter(t => t.isFeatured).map(template => (
                    <TemplateCard key={`featured-fallback-${template.id}`} template={{...template, isFeatured: false}} />
                  ))}
                </div>
              ) : (
                <div className="text-center py-16 animate-in fade-in duration-300" role="status">
                  <p className="text-gray-500 text-[15px]">No templates found. Try adjusting your filters.</p>
                  <button
                    onClick={() => { setRoleFilters([]); setUseCaseFilters([]); setSearchQuery(''); setCategoryFilter(''); }}
                    className="text-sm font-medium text-blue-500 hover:text-blue-600 hover:underline mt-3 focus:outline-none focus:ring-2 focus:ring-blue-500/50 rounded px-1"
                  >
                    Clear all filters
                  </button>
                </div>
              )}
            </section>
          </div>
        </div>
      </div>
    </div>
  );
}
